    def draw_verts(self, use_cverts):
        def f():
            pgl.glBegin(pgl.GL_LINE_STRIP)
            for t in range(len(self.t_set)):
                p = self.verts[t]
                if p is None:
                    pgl.glEnd()
                    pgl.glBegin(pgl.GL_LINE_STRIP)
                    continue
                if use_cverts:
                    c = self.cverts[t]
                    if c is None:
                        c = (0, 0, 0)
                    pgl.glColor3f(*c)
                else:
                    pgl.glColor3f(*self.default_wireframe_color)
                pgl.glVertex3f(*p)
            pgl.glEnd()
        return f
